import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "Blockchain Audit Trail",
  subtitle: "Immutable, cryptographically verified audit logs using blockchain technology",
  description: "Secure your compliance requirements with blockchain-verified audit trails. Every action, every access, and every change is recorded in an immutable ledger that cannot be tampered with, providing cryptographic proof of data integrity. Our blockchain-based system ensures complete transparency and traceability for all security events.",
  benefits: [
    "Immutable audit logs with blockchain verification",
    "Tamper-proof compliance reporting",
    "Cryptographic proof of data integrity",
    "Full traceability of all system actions",
    "Regulatory compliance automation"
  ],
  features: [
    { title: "Immutable Ledger", description: "All events recorded in distributed immutable storage" },
    { title: "Chain of Custody", description: "Complete chain of custody for all data access and modifications" },
    { title: "Digital Signatures", description: "Cryptographic signing of all audit events" },
    { title: "Verification API", description: "Programmatic verification of audit log integrity" },
    { title: "Compliance Reports", description: "Automated generation of compliance reports" }
  ],
  howItWorks: [
    { title: "Event Capture", description: "All security events are captured in real-time" },
    { title: "Hash Generation", description: "Each event is hashed using cryptographic algorithms" },
    { title: "Chain Storage", description: "Events are linked in a chain, making tampering impossible" },
    { title: "Verification", description: "Any party can verify the integrity of the audit trail" }
  ],
  color: "#10b981",
  icon: "M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10",
  gradient: "from-emerald-500 to-teal-500"
};

function BlockchainAudit() {
  return <FeatureDetail {...pageData} />;
}

export default BlockchainAudit;
